import{_ as p,c as t,o as a,ag as i}from"./chunks/framework.ELrfyV9R.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-15-vitepress.md","filePath":"ai/2026-03/2026-03-15-vitepress.md","lastUpdated":1773962024000}'),s={name:"ai/2026-03/2026-03-15-vitepress.md"};function r(o,e,n,g,l,d){return a(),t("div",null,e[0]||(e[0]=[i('<p>站在2030年的视角，AI时代，我们还有必要创建我们的个人门户网站吗?我们还有必要自己写点东西留存在互联网上吗？</p><p>现在不论什么问题，我都愿意先问问AI了，看看它能给我什么答案? 我相信已经有很多很多人跟我一样了。那么你有没有想过一个问题: AI给我们的这些高质量答案，又是从哪里来的呢?</p><p>答案其实就是: 来自AI“能看见”的地方。</p><p>同时最近爆火的315GEO数据投毒事件，某网上爆火，几乎所有人都能看到这个话题的内容。那么我这里就简单说一下GEO。</p><p>GEO（Generative Engine Optimization，也叫生成式引擎优化）是一种针对AI搜索引擎的内容优化策略。核心目标不是让你的网页排名靠前，而是让AI在回答用户问题时，<strong>直接引用你的内容、提及你的品牌。</strong></p><p>那我们应该怎么做呢？我可以在微信公众号、短视频、小红书、抖音、头条、知乎等等平台来构建自己的内容和品牌。而且完全可以做到全平台批量构建。 但是这些平台都有一个重大的弊端，我的内容或者我的账号，会在某个特定的早晨，因为一些各种各种的原因就面临某篇文章或视频的下架，甚至某个账号的永久封禁，从而导致我很多的内容资产消失。</p><p>所以当下我觉得AI时代，我的个人网站又必须排上日程了。它不再仅仅是给我记录笔记也好，构建内容和品牌也罢，学习当前最流行的AI前线技术也行。而更重要的一点，就是上面提及的让AI能更好的发现我们。</p><p>我们的网站可能被某某云下架，但是我们的内容在本地，在云端、在github，通过简单整改后仍然可以再次上线，甚至部署在别人无法触手可及的地方，只要不违背大的原因，他甚至可以永远存在。</p><p>而针对我们的网站，我们可以给它架设robots.txt确保AI能爬取到我们的内容，也给网站部署上llms.txt，告诉AI我是谁，我的网站干什么的，有什么内容，内容列表又是哪些，更多内容可以参考这篇文章</p><p><a href="https://x.com/YangGuangAI/status/2033522959407878621" target="_blank" rel="noreferrer">https://x.com/YangGuangAI/status/2033522959407878621</a></p><p>自媒体，独立开发者，现在流行的OPC，甚至越来越多的人，可能都在构建自己的个人独立网站。</p><p>说了那么多没用的，下面开始建造属于自己的避风港。</p><h2 id="项目整体搭建流程" tabindex="-1">项目整体搭建流程 <a class="header-anchor" href="#项目整体搭建流程" aria-label="Permalink to &quot;项目整体搭建流程&quot;">​</a></h2><ul><li>1、搭建本地环境</li><li>2、安装vitepress准备项目代码</li><li>3、上传github</li><li>4、</li></ul><h2 id="_1、搭建本地环境" tabindex="-1">1、搭建本地环境 <a class="header-anchor" href="#_1、搭建本地环境" aria-label="Permalink to &quot;1、搭建本地环境&quot;">​</a></h2><p>前置条件其实就是安装nodejs、git、obdisian客户端，如果没有的话可以让AI帮忙安装一下也可以自己手动进行下载，如果你本地没有AI工具，可以先下载使用Codex或者OpenCode，这两个客户端工具不需要其他依赖安装就可以使用，还是非常方便的，然后再来安装其他搭建所需的就可以了。 nodejs版本最好</p><p><strong>“帮我看看nodejs,git,obdisia客户端是否安装了，如果没安装帮我安装一下”</strong></p><p>![[Pasted image 20260320070923.png]]</p><p>箭头所示中间过程我已经省略了。</p><h2 id="_2、安装vitepress准备项目代码" tabindex="-1">2、安装vitepress准备项目代码 <a class="header-anchor" href="#_2、安装vitepress准备项目代码" aria-label="Permalink to &quot;2、安装vitepress准备项目代码&quot;">​</a></h2><p><strong>在当前文件夹下给我使用vitepress给我创建一个代码仓库</strong></p><p>![[Pasted image 20260320071109.png]]</p><p>依赖安装完毕，可以叫他本地直接跑项目看效果了。</p><p>![[Pasted image 20260320071316.png]]</p><p>看到访问地址基本就OK了，浏览器输入访问看效果。</p><p>![[Pasted image 20260315225949.png]]</p><p>网站运行OK了,接下来先将代码提交到github。</p><p>&quot;将项目上传到github&quot;</p><p>![[Pasted image 20260316061033.png]]</p><p>&quot;<a href="https://github.com/new" target="_blank" rel="noreferrer">https://github.com/new</a> 浏览器打开这个链接，直接创建项目&quot;</p><p>![[Pasted image 20260316063015.png]]</p><p>上面链接要先进行登录这里就不进行重点讲解了，主要就是箭头两个重点</p><ul><li>仓库名称，尽量用英文字母</li><li>choose visibility，我选择的public，意思就是开源，所有人都可以看到，另外一个private就是私有的，只有自己能看到。</li><li>剩下的你可以直接默认，也可以参考我的进行选择，然后点击右下角 Create repository。</li><li>仓库创建完毕就会直接跳转到当前仓库。</li></ul><p>![[Pasted image 20260316070834.png]]</p><p>“ <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:aehyok/vitepress-obsidian.git 这是我新创建的仓库，创建类型为public，请将当前仓库代码上传github”</p><p>![[Pasted image 20260317071023.png]]</p><p><a href="https://cloudflare.com" target="_blank" rel="noreferrer">https://cloudflare.com</a> 打开网站，如果没有账号就进行注册登录，登录之后右上角语言切换简体中文，设置完毕首页如下所示。</p><p>![[Pasted image 20260317153943.png]]</p><p>点击开始[构建]，进入页面会看到下面 [pages] 点击 开始使用 ![[Pasted image 20260317173522.png]]</p><p>进入页面后点击 导入现有Git存储库 开始使用，如果没关联过需要登录github进行授权的</p><p>选择 Only select repositories-&gt; Select repositories=-&gt; 文本框输入 obsidian-&gt; 选中代码仓库-&gt;点击绿色的 Save-&gt;稍等片刻会返回到cloudflare网站。也就是关闭弹窗。</p><p>![[Pasted image 20260317155017.png]]</p><p>回到cloudflare网站，选择好刚刚设置的仓库，点击右下角开始设置就可以了。</p><p>![[Pasted image 20260317174611.png]]</p><p>点击下一步 框架预设：选择VitePress 构建命令： npm vitepress build 构建输出目录：docs/.vitepress/dist</p><p>![[Pasted image 20260317181016.png]]</p><p>![[Pasted image 20260317175259.png]]</p><p>好了，兄弟们，网站有了。</p><p>![[Pasted image 20260317181210.png]] gh这玩意我没用过 “gh是什么”</p><p>![[Pasted image 20260316064929.png]]</p>',50)]))}const u=p(s,[["render",r]]);export{m as __pageData,u as default};
